def gen(rng, size):
    n = max(1, min(size, 100000))
    lines = max(2, n // 200)
    pts = []
    seen = set()
    while len(pts) < n:
        if rng.randint(0, 1) == 0:
            x = rng.randint(0, lines)
            y = rng.randint(-1000000000, 1000000000)
        else:
            x = rng.randint(-1000000000, 1000000000)
            y = rng.randint(0, lines)
        if (x, y) not in seen:
            seen.add((x, y))
            pts.append([x, y])
    return [pts]

