class Solution:
    def maxActivated(self, points):
        n = len(points)
        parent = list(range(n))
        def find(a):
            while parent[a] != a:
                parent[a] = parent[parent[a]]
                a = parent[a]
            return a
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        for i in range(n):
            for j in range(i + 1, n):
                if points[i][0] == points[j][0] or points[i][1] == points[j][1]:
                    union(i, j)
        counts = {}
        for i in range(n):
            r = find(i)
            counts[r] = counts.get(r, 0) + 1
        sizes = sorted(counts.values(), reverse=True)
        top1 = sizes[0] if sizes else 0
        top2 = sizes[1] if len(sizes) > 1 else 0
        return top1 + top2 + 1

