class Solution:
    def maxActivated(self, points):
        parent = {}
        size_pts = {}
        def find(a):
            parent.setdefault(a, a)
            root = a
            while parent[root] != root:
                root = parent[root]
            while parent[a] != root:
                parent[a], a = root, parent[a]
            return root
        for x, y in points:
            xn, yn = ('x', x), ('y', y)
            parent.setdefault(xn, xn)
            parent.setdefault(yn, yn)
            size_pts.setdefault(xn, 0)
            size_pts.setdefault(yn, 0)
            rx, ry = find(xn), find(yn)
            if rx == ry:
                size_pts[rx] = size_pts.get(rx, 0) + 1
            else:
                new_size = size_pts.get(rx, 0) + size_pts.get(ry, 0) + 1
                parent[rx] = ry
                size_pts.pop(rx, None)
                size_pts[ry] = new_size
        top1 = top2 = 0
        for v in size_pts.values():
            if v > top1:
                top1, top2 = v, top1
            elif v > top2:
                top2 = v
        return top1 + top2 + 1

