var maxActivated = function(points) {
    const parent = new Map();
    const sizePts = new Map();
    function find(a) {
        if (!parent.has(a)) parent.set(a, a);
        let root = a;
        while (parent.get(root) !== root) root = parent.get(root);
        while (parent.get(a) !== root) {
            const next = parent.get(a);
            parent.set(a, root);
            a = next;
        }
        return root;
    }
    for (const [x, y] of points) {
        const xn = 'x:' + x;
        const yn = 'y:' + y;
        if (!parent.has(xn)) parent.set(xn, xn);
        if (!parent.has(yn)) parent.set(yn, yn);
        if (!sizePts.has(xn)) sizePts.set(xn, 0);
        if (!sizePts.has(yn)) sizePts.set(yn, 0);
        const rx = find(xn);
        const ry = find(yn);
        if (rx === ry) {
            sizePts.set(rx, (sizePts.get(rx) || 0) + 1);
        } else {
            const newSize = (sizePts.get(rx) || 0) + (sizePts.get(ry) || 0) + 1;
            parent.set(rx, ry);
            sizePts.delete(rx);
            sizePts.set(ry, newSize);
        }
    }
    let top1 = 0, top2 = 0;
    for (const v of sizePts.values()) {
        if (v > top1) { top2 = top1; top1 = v; }
        else if (v > top2) { top2 = v; }
    }
    return top1 + top2 + 1;
};
